class Solution {
    public int makeTheIntegerZero(int num1, int num2) {
        if (num2 >= 0) {
            if (num1 % num2 == 0) {
                return num1 / num2;
            } else {
                return -1;
            }
        } else {
            int operations = 0;
            while (num1 > 0) {
                if (num1 < 60) {
                    if (num1 >= -num2) {
                        operations++;
                        return operations;
                    } else {
                        return -1;
                    }
                }
                num1 -= (1 << 60) + num2;
                operations++;
            }
            return operations;
        }
    }
}
